INSERT INTO public.photos VALUES (23686, 'Aer├│dromo Sanjurjo 1938', 'Imagen capturada en el aer├│dromo Sanjurjo de Zaragoza con un contundente primer plano de bombas de 50 kg. apiladas y listas para cargarlas en los bombarderos operativos. Tras ellas y en la pista, un Junkers Ju-W 34 Hi, aparato de enlace, entrenamiento y servicio meteorol├│gico, y varios Dornier Do-17 E.1, modernos bombarderos ligeros con capacidad de cargar 15 de estas bombas que los alemanes de la Legi├│n C├│ndor denominaban "Fliegender Bleistift" (l├ípiz volador) por su alargado fuselaje, y que los nacionalistas espa├▒oles redenominaron m├ís castizamente "Bacalao". Al fondo, l├¡nea de ├írboles que se├▒ala el curso del Canal Imperial de Arag├│n.', 1938, 1938, 1938, 'Anos 30', NULL, 41.66927300, -1.02867100, '0101000020E6100000737FF5B86F75F0BF438CD7BCAAD54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50301123318.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50301123318.webp', 'https://www.flickr.com/photos/zaragozaantigua/50301123318/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23057, 'Cuartel de Sementales 1994', 'Imagen capturada en el solar dejado tras el derribo de las instalaciones del cuartel 5┬║ Dep├│sito de Sementales sito en la calle del Asalto, entre el parque de Bruil y el Grupo de Viviendas Aloy Sala. Esta dependencia militar no fue incluida en la Operaci├│n Cuarteles a pesar de las gestiones del Ayuntamiento al principio de los a├▒os 80 por las reclamaciones realizadas por el ramo de la Guerra, tanto econ├│micas como que all├¡ se levantaran viviendas militares. En paralelo, el vecindario del barrio de las Tener├¡as promovi├│ gestiones para solicitar el traslado de este cuartel por sus afecciones insalubres, nocivas y molestas. Finalmente, en 1994 se lleg├│ a un acuerdo y el cuartel fue desmantelado y trasladado a unas nuevas instalaciones en Garrapinillos. El solar resultante ser├¡a objeto de un Plan Especial del ├ürea de Intervenci├│n U-7-2 aprobado en 1996 del que resultar├¡a la urbanizaci├│n actual de este espacio. En la escena, vista del solar dejado tras el derribo del cuartel, con el parque de Bruil al fondo, sobre el que emergen los bloques de la calle de Alvira Lasierra. A la derecha, viviendas de la calle del Asalto esquineras con la calle de Cant├¡n y Gamboa y vecinas del convento de las madres agustinas de Santa M├│nica. M├ís a la derecha, se destaca la torre del antiguo convento de San Agust├¡n.', 1994, 1994, 1994, 'Anos 90', 'CASCO HIST├ôRICO', 41.65102200, -0.86845600, '0101000020E6100000AF7AC03C64CAEBBFFE7C5BB054D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50449979087.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50449979087.webp', 'https://www.flickr.com/photos/zaragozaantigua/50449979087/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23201, 'Calle Vicente L├│pez Abad├¡a 2010', 'Foto: Oliver Duch. Solar entre las calles de Vicente L├│pez Abad├¡a (al fondo) y Pascual Albero Burillo, junto al parque Bruil. All├¡ se construy├│ en 2010 la Escuela Infantil Municipal Parque Bruil, inaugurada en octubre de 2012 con domicilio en la calle Vicente L├│pez Abad├¡a 4. En su subsuelo est├í previsto un aparcamiento subterr├íneo. Fuente: Heraldo de Arag├│n.', 2010, 2010, 2010, 'Siglo XXI', 'CASCO HIST├ôRICO', 41.65156300, -0.86685900, '0101000020E6100000D2C8E7154FBDEBBF4F24986A66D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32518208074.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32518208074.webp', 'https://www.flickr.com/photos/zaragozaantigua/32518208074/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24706, 'Prolongaci├│n Echegaray 1989', 'Vista a├®rea de las obras de 1989 en el entorno de la desembocadura del r├¡o Huerva, en lo que ser├í la prolongaci├│n del paseo de Echegaray y Caballero. En primer t├®rmino, construcci├│n del puente de La Uni├│n. En el centro, puente sobre el Huerva. Al fondo a la derecha, puentes del Pilar, de Piedra y de Santiago. Fuente: www.eszaragoza.eu/2017/06/lo-que-sucedia-en-zaragoza-dura...', 1989, 1989, 1989, 'Anos 80', 'CASCO HIST├ôRICO', 41.65240600, -0.86526100, '0101000020E6100000DD2230D637B0EBBF6ADB300A82D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/36403250961.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/36403250961.webp', 'https://www.flickr.com/photos/zaragozaantigua/36403250961/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24736, 'El Huerva llega al Ebro 1977', 'Imagen de la desembocadura del Huerva en el Ebro. Pocos cambios en este entorno desde que el Huerva abandonara, hace ya bastante tiempo, su antiguo cauce, por la actual calle del Asalto, y se desviara hacia la derecha, hacia tierras m├ís bajas, dejando el meandro del actual Parque Bruil como un lugar muy favorable para la agricultura. En la margen izquierda, panorama de las diferentes urbanizaciones, en este caso con grandes bloques habitacionales que iban surgiendo desde mediados de los a├▒os 70. En primer t├®rmino, sobresaliendo detr├ís de naves y almacenes, la urbanizaci├│n Vadorrey. A la izquierda, m├ís al fondo, la urbanizaci├│n denominada "El Colector", actual Manuel Viola. El alto bloque que sobresale por encima de todos, es el edificio "La Estrella", de 14 alturas, junto a la Avenida de Catalu├▒a. Fuente visual: "La evoluci├│n urbana de Zaragoza al este del Huerva", Carmen Santos Vich, 1978.', 1977, 1977, 1977, 'Anos 70', 'CASCO HIST├ôRICO', 41.65295400, -0.86484000, '0101000020E610000078B988EFC4ACEBBF6DE525FF93D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15139541264.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15139541264.webp', 'https://www.flickr.com/photos/zaragozaantigua/15139541264/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24961, 'Al norte del Parque Bruil 1974', 'AYUNTAMIENTO DE ZARAGOZA/Sancho Ramo, Gerardo/Noviembre 1974. La Torre de Bruil-Parque Bruil, el Dep├│sito de Sementales del Ej├®rcito de Tierra, el Grupo de Viviendas "Aloy Sala" (Arrabal de las Tener├¡as), y el r├¡o Huerva ya casi desembocando en el Ebro, delimitaban una interesante y poco visitada zona de antiguos campos de cultivo, a escasos minutos del centro de la ciudad. Dos principales caminos de servicio de fincas hac├¡an las funciones de irregular cardo y decumano para un llano per├¡metro donde cereales y herb├íceas se suced├¡an seg├║n el a├▒o. Un riego derivado de acequia, y un desag├╝e de viejos lavaderos, vert├¡an aguas a la trinchera del Huerva (a la izquierda). El desarrollo urbano de la ciudad hab├¡a sido orientado hacia otras latitudes, y el entorno no se consideraba de la suficiente calidad como para esperar una revalorizaci├│n suficiente y r├ípida del precio del suelo agr├¡cola. Pese a tener de vecino al nov├¡simo y espectacular Parque Bruil, la inmediatez del cuartel del Ej├®rcito (caballer├¡a), las viviendas baratas de los 50, y que las Tener├¡as no era precisamente el Soho zaragozano, mantuvo en barbecho espectante esta zona durante alguna d├®cada m├ís. Ahora esto es otra cosa, distinta. En la imagen, vista de los campos de cultivo desde la actual calle Alto Arag├│n. De izquierda a derecha, el r├¡o Huerva, el reciente edificio H├íbitat Don 2000 (1973), y tras el muro de delimitaci├│n, los ├írboles y fronda del Parque Bruil, y las arom├íticas instalaciones del cuartel de caballer├¡a. Justo detr├ís, las ruinas del antiguo convento de S. Agust├¡n y su caracter├¡stica y desmochada torre, y la confluencia viaria de Alonso V con la calle Asalto.', 1974, 1974, 1974, 'Anos 70', 'CASCO HIST├ôRICO', 41.65139800, -0.86796800, '0101000020E6100000552FBFD364C6EBBF0457790261D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14849195251.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14849195251.webp', 'https://www.flickr.com/photos/zaragozaantigua/14849195251/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24963, 'Parque Bruil 1965', 'Ayuntamiento de Zaragoza/Gerardo Sancho Ramo/julio 1965. Tras m├ís de diez a├▒os de gestiones, inauguraci├│n del municipal Parque Bruil, entre el r├¡o Huerva (este), la calle Asalto (oeste), el cuartel de Sementales y unos campos de cultivos (norte), y un vial que poco despu├®s se denominar├í Mariano Alvira Lasierra.', 1965, 1965, 1965, 'Anos 60', 'CASCO HIST├ôRICO', 41.64977900, -0.86902400, '0101000020E6100000240D6E6B0BCFEBBF555051F52BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14850897742.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14850897742.webp', 'https://www.flickr.com/photos/zaragozaantigua/14850897742/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24974, 'Parque Bruil 1970', 'Piscinas del parque Bruil de Zaragoza. Postal, ed. Zerkowitz, serie 82, n┬║ 1.074, 1970. Fuente: www.todocoleccion.net', 1970, 1970, 1970, 'Anos 70', 'CASCO HIST├ôRICO', 41.64977900, -0.86902400, '0101000020E6100000240D6E6B0BCFEBBF555051F52BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19585124351.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19585124351.webp', 'https://www.flickr.com/photos/zaragozaantigua/19585124351/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25421, 'R├¡o Ebro y murallas s.XVII', 'Trascoro de la Seo de Zaragoza. Siglo XVII. Relieve de la vista del r├¡o Ebro y las murallas de Zaragoza con la puerta del ├üngel junto al puente de Piedra, y el puente de Tablas en primer t├®rmino. Escena de la leyenda del hallazgo del los restos de Santo Dominguito de Val decapitado. Fuente: Cat├ílogo El municipio en Arag├│n, DPZ, 2004.', NULL, NULL, NULL, NULL, 'CASCO HIST├ôRICO', 41.65285400, -0.86416000, '0101000020E6100000105D50DF32A7EBBF098849B890D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18672417202.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18672417202.webp', 'https://www.flickr.com/photos/zaragozaantigua/18672417202/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25536, 'Colector del Huerva 1934', 'El emisario del alcantarillado al r├¡o Ebro en la margen izquierda de la desembocadura del Huerva fue construido en 1907 y ampliado en 1934, momento que recoge la foto. Entre los trabajadores, algunas bestias de carga. Hasta la urbanizaci├│n reciente de la zona en el siglo XXI, el colector vert├¡a las aguas residuales al descubierto, dejando un olor caracter├¡stico. Fuente: Plan general de ensanche de Zaragoza, 1934.', 1934, 1934, 1934, 'Anos 30', 'CASCO HIST├ôRICO', 41.65312700, -0.86547500, '0101000020E6100000E02D90A0F8B1EBBF3A9160AA99D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18701889484.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18701889484.webp', 'https://www.flickr.com/photos/zaragozaantigua/18701889484/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23059, 'Vuelta ciclista a Espa├▒a 1990', 'El 13 de mayo de 1990 se celebr├│ la etapa 19 de la Vuelta ciclista a Espa├▒a, con un recorrido de 30 km contrarreloj dentro de la ciudad de Zaragoza. El ganador de la prueba fue Peio Ruiz Cabestany, y el de la Vuelta, Marco GIovannetti. La imagen est├í extra├¡da del v├¡deo de la retransmisi├│n en TVE, y muestra al ciclista Pedro Delgado atravesando el puente de la Uni├│n o de Las Fuentes sobre el Ebro, con el Pilar al fondo.', 1990, 1990, 1990, 'Anos 90', 'CASCO HIST├ôRICO', 41.65246900, -0.86273700, '0101000020E6100000A79201A08A9BEBBFB153AC1A84D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50494089228.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50494089228.webp', 'https://www.flickr.com/photos/zaragozaantigua/50494089228/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21222, 'R├¡o Ebro c.1905', 'Photoglob Z├╝rich. Ca.1905. "R├¡o Ebro y Nuestra Se├▒ora del Pilar". Imagen del Ebro, con el fluvial paso en barca, por a├®reo camino de sirga, del "T├¡o Toni". Al fondo, el puente de las piedras, con sus pretiles y sus leones. Detr├ís, el de hierros. Fuente: www.el-trastero.eu/caddie/images/zaragoza-0010.webp', 1905, 1905, 1905, 'Anos 1900', 'CASCO HIST├ôRICO', 41.65911000, -0.88090100, '0101000020E61000003370404B5730ECBFB83B6BB75DD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15934073422.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15934073422.webp', 'https://www.flickr.com/photos/zaragozaantigua/15934073422/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21442, 'R├¡o Ebro c.1910', 'Imagen capturada junto a la ribera del r├¡o Ebro inmediata a la arboleda de Macanaz, en la margen izquierda, y centrada en una vista que incluye al Puente de Piedra y el Puente de Hierro m├ís al fondo, y el templo del Pilar con las dos torres recayentes a la hom├│nima plaza. En primer t├®rmino, embarcadero del paso de barcas que d├®cadas m├ís tarde se├▒alar├¡a la ubicaci├│n de una pasarela peatonal permanente. Sobre el Puente de Piedra transita un coche posiblemente de la tranviaria l├¡nea del Arrabal. A la derecha, entre el Pilar y la ribera de la margen derecha, el recoleto espacio junto a la Puerta del Fin y la Escuela Normal de Maestras utilizado como ferial de ganado.', 1910, 1910, 1910, 'Anos 10', 'CASCO HIST├ôRICO', 41.65886900, -0.88098700, '0101000020E6100000D66F26A60B31ECBF93ACC3D155D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49334482061.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49334482061.webp', 'https://www.flickr.com/photos/zaragozaantigua/49334482061/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21502, 'Almadieros 1923', 'Miguel Faci Abad. 1923. "Zaragoza. Ba├▒os del Ebro y navatas." En la imagen, tomada desde la margen izquierda del r├¡o Ebro, aspecto de la arboleda de Macanaz cuando a├║n era utilizada para desembarcar los maderos que los almadieros del Valle del Roncal tra├¡an a la ciudad. Los maderos, una vez sacados del agua, se dejaban "en cuarentena", para que se secaran completamente antes de su uso, o distribuci├│n. Mientras los almadieros descansan al sol de la tarde, unos chavales en pelota picada se remojan para refrescarse, mientras otros, vestidos, se van a remojar sin pretenderlo. El uso del Ebro como fluvial ruta de transporte de madera fue posible hasta la puesta en funcionamiento de la presa de Yesa (1959-1960). Fuente visual: "Miguel y Gabriel Faci. Fot├│grafos fundadores de la Real Sociedad Fotogr├ífica de Zaragoza.", Alfredo Romero y Ricardo Centellas, Diputaci├│n Provincial de Zaragoza, 1999.', 1923, 1923, 1923, 'Anos 20', 'CASCO HIST├ôRICO', 41.65911000, -0.88090100, '0101000020E61000003370404B5730ECBFB83B6BB75DD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15516887172.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15516887172.webp', 'https://www.flickr.com/photos/zaragozaantigua/15516887172/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21685, 'El paso del Ebro 1939', 'Albert Louis Deschamps. Cruzando el Ebro a mano, a la altura de San Juan de los Panetes y la Zuda, una maniobra de la Barca del T├¡o Toni, al precio de cinco c├®ntimos de peseta la persona. El Torre├│n de la Zuda se encontraba entre diversas viviendas que se le hab├¡an ido adosando a lo largo del tiempo. En 1931 comenzar├í una intervenci├│n en la zona, con la ampliaci├│n de la avenida de Nuestra Se├▒ora del Pilar, las murallas romanas, el torre├│n de la Zuda y la iglesia de San Juan de los Panetes. Luego vendr├í la idea de la V├¡a Imperial, y luego la de C├®sar Augusto... En la imagen a├║n no estaba construida la Pasarela Peatonal sobre el Ebro, que se iniciar├í en 1940, y se inaugurar├í en 1941.', 1939, 1939, 1939, 'Anos 30', 'CASCO HIST├ôRICO', 41.65835600, -0.88138400, '0101000020E61000001AF7E6374C34ECBF0C90680245D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14903094946.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14903094946.webp', 'https://www.flickr.com/photos/zaragozaantigua/14903094946/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21734, 'El Ebro y el Pilar a├▒os 30', 'Foto: Miguel Mar├¡n Chivite. Panorama del r├¡o Ebro con el Pilar al fondo. A la izquierda, puente de piedra y ni├▒o bebiendo. La embarcaci├│n que aparece es un modelo motorizado que efect├║a el recorrido tradicional de la barca del T├¡o Toni, que seguir├í prestando sus servicios mediante sirga a mano hasta la construcci├│n de la pasarela peatonal en los a├▒os 40. Fuente: Archivo Heraldo de Arag├│n.', 1930, 1930, 1939, 'Anos 30', 'CASCO HIST├ôRICO', 41.65835600, -0.88148800, '0101000020E610000058207A522635ECBF0C90680245D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21351091648.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21351091648.webp', 'https://www.flickr.com/photos/zaragozaantigua/21351091648/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21773, 'R├¡o Ebro 1932', 'R├¡o Ebro. Al fondo, el puente del Ferrocarril. A la derecha, la arboleda de Macanaz, la Caseta de Ba├▒os, y la ÔÇ£Sociedad Naturista HeliosÔÇØ. Una barca cruza el r├¡o. Fuente visual: Foto Conrado Barl├®s, donada por Daniel Barl├®s y digitalizada por Jos├® Luis Cintora para www.rafaelcastillejo.com', 1932, 1932, 1932, 'Anos 30', 'CASCO HIST├ôRICO', 41.65854900, -0.88066500, '0101000020E61000003C6BB75D682EECBF21E868554BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22855738617.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22855738617.webp', 'https://www.flickr.com/photos/zaragozaantigua/22855738617/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21829, 'Embarcadero 1933', 'Embarcadero en el r├¡o Ebro. Al fondo, el Pilar. Fuente: Heraldo de Arag├│n.', 1933, 1933, 1933, 'Anos 30', 'CASCO HIST├ôRICO', 41.65897000, -0.88242700, '0101000020E6100000C16F438CD73CECBFC685032159D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32935400752.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32935400752.webp', 'https://www.flickr.com/photos/zaragozaantigua/32935400752/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21842, 'Pasarela de Macanaz 1933', 'Dibujo representando la pasarela peatonal sobre el r├¡o Ebro proyectada por el ingeniero Luis de Fuentes L├│pez como forma de conectar la calle de Antonio P├®rez con la arboleda de Macanaz. El antropol├│gico y ├║nico paso de sirga del t├¡o Toni ya hab├¡a dado paso a la introducci├│n por ├üngel Bag├╝├®s de las modernas barcas a gasolina que cubr├¡an el tr├ínsito de personas entre las dos orillas mediante varios embarcaderos. Tras los diversos procesos de embellecimiento de ambas riberas del Ebro, ahora parec├¡a tocarle el turno a la construcci├│n de un paso peatonal estable de orilla a orilla, si bien la idea finalmente ser├¡a materializada al principio de la siguiente d├®cada, tan cercana, y tan diferente. En el dibujo, la proyectada pasarela representada entre la orilla derecha (a la izquierda) con el final de la calle de Antonio P├®rez, y la orilla izquierda (a la derecha) con la arboleda de Macanaz y su acceso casi cinco metros m├ís bajo a salvar mediante escaleras. Fuente visual: www.mecd.gob.es/.', 1933, 1933, 1933, 'Anos 30', 'CASCO HIST├ôRICO', 41.65843900, -0.88113600, '0101000020E61000001381EA1F4432ECBF9AB4A9BA47D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/35569416784.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/35569416784.webp', 'https://www.flickr.com/photos/zaragozaantigua/35569416784/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21844, 'Calle de Demetrio Gal├ín 1934', 'Imagen capturada en la despejada calle de Demetrio Gal├ín, paralela a la arboleda de Macanaz, y centrada en la f├íbrica de lavaje y apartado de lanas de Jaime Corcoy, que inici├│ su actividad en 1917 como Manufactura de Lanas de Mor├│n y An├│s, con dise├▒o de Miguel ├üngel Navarro, en el entonces camino de Ranillas. De esta instalaci├│n perdura la chimenea, en un entorno descontextualizado, bastante diferente. Fuente visual: www.mecd.gob.es/.', 1934, 1934, 1934, 'Anos 30', 'CASCO HIST├ôRICO', 41.66064300, -0.88270300, '0101000020E61000004698A25C1A3FECBF69AA27F38FD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/35653992904.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/35653992904.webp', 'https://www.flickr.com/photos/zaragozaantigua/35653992904/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22037, 'R├¡o Ebro c.1942', 'Acuarela del prol├¡fico dibujante, poeta y periodista Ambrosio Ruste Alonso (1871-1955) titulada "El Pilar" porque este templo centra desde el fondo de la escena una fluvial vista capturada desde un embarcadero recreativo en la arboleda de Macanaz. Apenas esbozada, la pasarela del Ebro aparece levemente tendida sobre el r├¡o. Fue proyectada en 1933 por el ingeniero Luis de Fuentes L├│pez como forma de conectar la calle de Antonio P├®rez con la arboleda de Macanaz, si bien su construcci├│n se demor├│ en el tiempo para ser finalmente bendecida e inaugurada el 25 de febrero de 1941, terminando as├¡ con la tradicional barca de sirga que desde el siglo XIX conectaba las dos riberas y que desde los a├▒os 30 fue sustituida por "gasolineras" o barcazas a motor. Como siempre, una mejora en esta ciudad que conlleva un derribo o una desaparici├│n de un elemento previo fue ardorosamente aplaudida en la prensa de la ├®poca, donde se sentenci├│ que la referida barca era "vieja", "antiest├®tica" y "lenta", mientras que la nueva pasarela era "m├ís l├│gica, c├│moda y eficaz". As├¡ las cosas y de forma no menos l├│gica, esta situaci├│n se repetir├¡a casi un cuarto de siglo despu├®s, cuando esta pasarela fue desmontada para dar paso a un nuevo puente m├ís c├│modo y eficaz.', 1942, 1942, 1942, 'Anos 40', 'CASCO HIST├ôRICO', 41.65914200, -0.88259600, '0101000020E6100000C59272F7393EECBFC4B5DAC35ED44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54754018338.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54754018338.webp', 'https://www.flickr.com/photos/zaragozaantigua/54754018338/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22082, 'Pasarela sobre el Ebro a├▒os 50', 'Magn├¡fica imagen del acceso desde la Arboleda de Macanaz a la pasarela sobre el r├¡o Ebro construida en 1941, que desapareci├│ para dar paso al puente de Santiago en 1967. Al fondo, la iglesia de San Juan de los Panetes. Fuente: www.facebook.com/photo.php?fbid=643306315778704&set=p...', 1950, 1950, 1959, 'Anos 50', 'CASCO HIST├ôRICO', 41.65902300, -0.88117100, '0101000020E61000002FE065868D32ECBFE9279CDD5AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15783586076.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15783586076.webp', 'https://www.flickr.com/photos/zaragozaantigua/15783586076/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22095, 'Pasarela 1955', '"Saliendo de la escuela", foto de Jos├® Antonio Duce, 1955. Ni├▒os sobre la pasarela peatonal del Ebro que ser├í sustituida por el puente de Santiago. Al fondo, San Juan de los Panetes. Fuente: rafaelcastillejo.com', 1955, 1955, 1955, 'Anos 50', 'CASCO HIST├ôRICO', 41.65859700, -0.88151900, '0101000020E610000019AF79556735ECBF321F10E84CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20090004454.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20090004454.webp', 'https://www.flickr.com/photos/zaragozaantigua/20090004454/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22230, 'Helios c.1959', 'Imagen capturada desde el campin de Helios y orientada hacia el este, con vista parcial de la original piscina y la pista de baloncesto. Hacia el fondo, la arboleda de Macanaz, flanqueada por viviendas del Arrabal a la izquierda, y el templo del Pilar a la derecha.', 1959, 1959, 1959, 'Anos 50', 'CASCO HIST├ôRICO', 41.66000800, -0.88296100, '0101000020E61000003197546D3741ECBF978C63247BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49911991977.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49911991977.webp', 'https://www.flickr.com/photos/zaragozaantigua/49911991977/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22289, 'Puente de Santiago 1965', 'Archivo Municipal de Zaragoza. Gerardo Sancho Ramo. 23/01/1965. "Crecida del r├¡o Ebro." 1965 fue otro a├▒o de crecida destacable del r├¡o Ebro. A su paso por la ciudad, la altura del agua fluyendo alcanz├│ los cinco metros de altura. En la imagen, aspecto del puente de Santiago en construcci├│n, mientras el cauce se hinchaba y desbordaba all├¡ donde las riberas lo permit├¡an, como en la zona de Helios.', 1965, 1965, 1965, 'Anos 60', 'CASCO HIST├ôRICO', 41.65856500, -0.88158800, '0101000020E61000003A799109F835ECBF27A5A0DB4BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15208136758.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15208136758.webp', 'https://www.flickr.com/photos/zaragozaantigua/15208136758/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22313, 'Pasarela Ebro 1962', 'Jos├® Antonio Duce. 1962. Imagen de la Pasarela Peatonal del Ebro. Captura de imagen desde la Margen Izquierda. En la ribera derecha, marcado contraluz para la fachada de edificios al paseo del Ebro. Entre las sombras, el dieciochesco antiguo Almac├®n de la Sal, junto a algunas otras edificaciones que siglo de las Luces, que a├▒os despu├®s terminar├¡an cayendo derrumbados por piquetas y mec├ínicos ingenios. Fuente visual: www.gozazaragoza.com/contenido.php?id=9799', 1962, 1962, 1962, 'Anos 60', 'CASCO HIST├ôRICO', 41.65902300, -0.88117100, '0101000020E61000002FE065868D32ECBFE9279CDD5AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15747149020.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15747149020.webp', 'https://www.flickr.com/photos/zaragozaantigua/15747149020/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22356, 'El Pilar a├▒os 60', 'Foto: Colecci├│n Adolfo Mart├¡nez. Pirag├╝istas en el r├¡o Ebro, con el Pilar al fondo. Fuente: rafaelcastillejo.com', 1960, 1960, 1969, 'Anos 60', 'CASCO HIST├ôRICO', 41.65853000, -0.88008800, '0101000020E6100000FA43334FAE29ECBFAAB706B64AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20712101535.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20712101535.webp', 'https://www.flickr.com/photos/zaragozaantigua/20712101535/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22357, 'Puente Santiago 1964', 'Foto: Emilio Gil. Construcci├│n del Puente de Santiago de Zaragoza, con los restos de la estructura de la pasarela en primer plano y la Margen Izquierda al fondo. Fuente: rafaelcastillejo.com', 1964, 1964, 1964, 'Anos 60', 'CASCO HIST├ôRICO', 41.65859700, -0.88151900, '0101000020E610000019AF79556735ECBF321F10E84CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20715635991.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20715635991.webp', 'https://www.flickr.com/photos/zaragozaantigua/20715635991/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22364, 'Esqu├¡ acu├ítico c.1969', 'Postal, finales de los a├▒os 60. Vista del puente de Santiago sobre el r├¡o Ebro en Zaragoza, con baturros en primer plano y una lancha practicando esqu├¡ acu├ítico, deporte que no ha llegado a cuajar entre los tradicionales aragoneses. Fuente: www.facebook.com/photo.php?fbid=10201037600339410&set...', 1969, 1969, 1969, 'Anos 60', 'CASCO HIST├ôRICO', 41.65908400, -0.88194800, '0101000020E610000034B91803EB38ECBF8FA850DD5CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21268207276.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21268207276.webp', 'https://www.flickr.com/photos/zaragozaantigua/21268207276/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22431, 'Vista a├®rea 1966', 'Canicular vista a├®rea centrada en la construcci├│n del nuevo puente sobre el r├¡o Ebro y la apertura en la margen izquierda de la avenida de los Pirineos como inicio de la moderna carretera hacia Huesca. En la margen derecha, aun con los derribos de viviendas de la antigua calle de Antonio P├®rez (moderna V├¡a Imperial y luego avenida de C├®sar Augusto), el tr├ínsito rodado se habr├¡a de topar, indefectiblemente, con el Mercado Central (en primer t├®rmino), construido en los albores del siglo cuando ninguna mente con visi├│n de futuro pudo siquiera so├▒ar que las necesidades de movilidad de un gran parque autom├│vil habr├¡an de requerir practicar cirug├¡a urban├¡stica radical en el casco antiguo de la ciudad. No pasar├¡an muchos a├▒os hasta que se fomentara la bochornosa campa├▒a que exig├¡a derribar el Mercado Central para dar paso a la modernidad identificada con la hegemon├¡a del veh├¡culo privado, y la adecuaci├│n viaria a sus exponenciales necesidades de espacio. Fuente: TAF Helic├▓pters SA, en Arxiu Nacional de Catalunya.', 1966, 1966, 1966, 'Anos 60', 'CASCO HIST├ôRICO', 41.65858700, -0.88163100, '0101000020E61000000C7904375236ECBF0E492D944CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/29290884717.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/29290884717.webp', 'https://www.flickr.com/photos/zaragozaantigua/29290884717/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22434, 'Puente de Santiago 1966', 'Imagen capturada durante la construcci├│n del "Nuevo puente sobre el r├¡o Ebro" por el M.O.P., con interesante vista en la margen izquierda del barrio de la Hortilla (antes de perder la "h") y aun del de Ranillas, el ribere├▒o camping de Helios, el antiguo edificio de los "Ba├▒os del Ebro" y, sobresaliendo entre la foresta, la chimenea de la antigua "Manufacturas de lanas de Mor├│n y An├│s", en el Camino de Ranillas. Al fondo, a la izquierda, el puente del ferrocarril. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1966, 1966, 1966, 'Anos 60', 'CASCO HIST├ôRICO', 41.65859700, -0.88151900, '0101000020E610000019AF79556735ECBF321F10E84CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30235519295.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30235519295.webp', 'https://www.flickr.com/photos/zaragozaantigua/30235519295/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22451, 'Puente de Santiago 1966', 'Imagen, capturada desde la margen izquierda, durante la construcci├│n del nuevo puente sobre el r├¡o Ebro que sustituy├│ a la pasarela peatonal. A la izquierda, vista parcial de la obra de la piscina cubierta del Club Nataci├│n Helios, ubicada donde estuviera el antiguo edificio de los Ba├▒os del Ebro. Una interesante crecida del r├¡o pone a prueba las obras, aunque no tiene la descomunal categor├¡a de las de 1643, o 1871, entre otras cosas, por las obras de regulaci├│n en cabecera de cuenca. Fuente visual: foto Gerardo Sancho Ramo, AMZ.', 1966, 1966, 1966, 'Anos 60', 'CASCO HIST├ôRICO', 41.65859700, -0.88151900, '0101000020E610000019AF79556735ECBF321F10E84CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31407744436.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31407744436.webp', 'https://www.flickr.com/photos/zaragozaantigua/31407744436/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22488, 'Puente de Santiago 1966', 'Veraniega vista panor├ímica capturada en altura y centrada en la construcci├│n del nuevo puente sobre el r├¡o Ebro que, denominado de Santiago, supuso el desmontaje de la previa pasarela peatonal de pago, la apertura para el tr├ífico rodado en la margen izquierda de la gran avenida de los Pirineos como inicio de la moderna carretera hacia Huesca, y en la margen derecha la consolidaci├│n de la avenida de C├®sar Augusto como v├¡a de alta capacidad que habr├¡a de conducir el tr├ífico, tras despejar el camino por una parte de la antigua ciudad, hasta la misma puerta del Carmen. En primer t├®rmino, la arbolada zona oriental de la gran plaza del Pilar determinada por el referencial monumento "A los h├®roes y m├írtires de Zaragoza ca├¡dos en nuestra Gloriosa Cruzada de Liberaci├│n 1936-1939", la iglesia de San Juan de los Panetes y el torre├│n de la Zuda. En la margen izquierda, la arboleda de Macanaz, el Club Nataci├│n Helios en proceso de ampliaci├│n de instalaciones, la antigua factoria "Manufacturas de lanas de Mor├│n y An├│s", el barrio de la Ortilla y el tendido del enlace ferroviario hacia Alsasua. Fuente: TAF Helic├▓pters SA, en Arxiu Nacional de Catalunya.', 1966, 1966, 1966, 'Anos 60', 'CASCO HIST├ôRICO', 41.65852500, -0.88135200, '0101000020E61000004374081C0934ECBF984C158C4AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/44125666581.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/44125666581.webp', 'https://www.flickr.com/photos/zaragozaantigua/44125666581/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22569, 'Vista del Ebro c.1977', 'Postal. Vista a├®rea del r├¡o Ebro cruzado por el puente de Santiago, desde la margen izquierda. La masa frondosa dividida por el Segundo Cintur├│n es la Arboleda de Macanaz. A la derecha, el Club Nataci├│n Helios, con su piscina cubierta construida en 1976. Al fondo, la vieja ciudad, con el Pilar como referencia vertical. Fuente visual: www.delcampe.net/', 1977, 1977, 1977, 'Anos 70', 'CASCO HIST├ôRICO', 41.65910000, -0.88142000, '0101000020E61000004D4A41B79734ECBF956588635DD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15295952888.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15295952888.webp', 'https://www.flickr.com/photos/zaragozaantigua/15295952888/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22918, 'Baturros y Pilar a├▒os 80', 'Pareja de baturros con el Pilar al fondo. Fuente: Foto para postal de Comercial Josan. Cesi├│n de la familia de Jos├® Mar├¡a Sanz Gonz├ílez a Rafael Castillejo. Dataci├│n y procesado:', 1980, 1980, 1989, 'Anos 80', 'CASCO HIST├ôRICO', 41.65910700, -0.87989500, '0101000020E6100000D53E1D8F1928ECBF47C8409E5DD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27422065605.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27422065605.webp', 'https://www.flickr.com/photos/zaragozaantigua/27422065605/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22956, 'Av. de los Pirineos 1981', 'Imagen capturada durante la salida desde Zaragoza de la antorcha que anunciaba la celebraci├│n de la Universiada de Invierno en el Pirineo Aragon├®s, en instalaciones de Formigal, Candanch├║, Ast├║n, Panticosa, y Jaca, donde se celebrar├¡an entre otros actos las ceremonias de apertura, el d├¡a 24 de febrero, y la de clausura, el 4 de marzo. El fallido Golpe de Estado del 23 de febrero estuvo a punto de hacer que se suspendiera este evento deportivo, que finalmente tuvo lugar las fechas previstas con m├ís que notable presencia de Polic├¡a, Guardia Civil, y Ej├®rcito. Este "Circo Blanco" fue el pistoletazo de salida de la carrera en pos del sue├▒o, o pesadilla, de organizar una Olimpiada de Invierno en la Jacetania, que se prolongar├í en el tiempo. Al fondo de la imagen, arboleda de Macanaz y el templo metropolitano del Pilar.', 1981, 1981, 1981, 'Anos 80', 'CASCO HIST├ôRICO', 41.66020700, -0.88126600, '0101000020E61000009F7422C15433ECBF8ECBB8A981D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48641710017.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48641710017.webp', 'https://www.flickr.com/photos/zaragozaantigua/48641710017/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23818, 'Paseo del Ebro 1927', 'Marcelino Secorum, 1927. Dibujo del anteproyecto (no realizado) de embellecimiento del paseo del Ebro. Perspectiva de conjunto. Fuente: Archivo Municipal de Zaragoza.', 1927, 1927, 1927, 'Anos 20', 'CASCO HIST├ôRICO', 41.65837200, -0.88201700, '0101000020E6100000568330B77B39ECBF124DA08845D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18650377766.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18650377766.webp', 'https://www.flickr.com/photos/zaragozaantigua/18650377766/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23826, 'El Pilar c.1864', 'Vista del Pilar desde la Margen Izquierda. Fuente visual: original de Ferrier et Soulier editada por J. L├®vy & C├¡a, publicada en el libro de viajes "Spain and the spaniards", Edmondo De Amicis, edici├│n 1895. ("Espa├▒a", viaje durante el reinado de Amadeo I de Saboya).', 1864, 1864, 1864, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65864200, -0.88221200, '0101000020E6100000A87004A9143BECBFD2E28C614ED44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20725320782.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20725320782.webp', 'https://www.flickr.com/photos/zaragozaantigua/20725320782/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24355, 'Barca y pasarela 1940', 'Construcci├│n de la pasarela sobre el Ebro a la altura de San Juan de los Panetes, que estar├í en servicio hasta la inauguraci├│n del puente de Santiago, en 1967. Mientras van acab├índola, la c├®lebre barca del T├¡o Toni contin├║a llevando de orilla a orilla a la gente, con su sirga. En 1935 el MOPU hab├¡a otorgado una concesi├│n para la construcci├│n de una pasarela que comunica ambas orillas del Ebro. Se construy├│ en 1940, y se abri├│ al servicio p├║blico en 1941. El proyecto fue del ingeniero Luis Fuentes L├│pez. La construcci├│n y montaje de la parte met├ílica de la pasarela se hizo por "Maquinista y Fundiciones del Ebro, S.A." Dirigi├│ la obra de f├íbrica complementaria Enrique Bressel. Funcionaba la pasarela d├¡a y noche.', 1940, 1940, 1940, 'Anos 40', 'CASCO HIST├ôRICO', 41.65832400, -0.88150600, '0101000020E6100000F14927124C35ECBF0116F9F543D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14934310221.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14934310221.webp', 'https://www.flickr.com/photos/zaragozaantigua/14934310221/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24675, 'Puente Santiago c.1979', 'Un hombre pasea una mula por el puente de Santiago de Zaragoza. Al fondo, la Cruz de los Ca├¡dos, San Juan de los Panetes, el torre├│n de la Zuda y el Mercado Central. Fuente: www.facebook.com/photo.php?fbid=1578563142386483&set=...', 1979, 1979, 1979, 'Anos 70', 'CASCO HIST├ôRICO', 41.65835600, -0.88148800, '0101000020E610000058207A522635ECBF0C90680245D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20723475792.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20723475792.webp', 'https://www.flickr.com/photos/zaragozaantigua/20723475792/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24681, 'R├¡o Ebro 1872', '"R├¡o Ebro y San Juan de los Panetes", ├│leo sobre tabla, Francisco Pradilla, 1872. Vista del r├¡o Ebro desde la arboleda de Macanaz, con la silueta de San Juan de los Panetes al fondo. Fuente: Zaragoza vista por los artistas, 1908-2008.', 1872, 1872, 1872, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65853000, -0.88008800, '0101000020E6100000FA43334FAE29ECBFAAB706B64AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32234419582.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32234419582.webp', 'https://www.flickr.com/photos/zaragozaantigua/32234419582/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24738, 'Puente de Santiago 1967', '"Gente en el reci├®n inaugurado Puente de Santiago." Aun la gente ind├¡gena, tres semanas despu├®s de su oficial inauguraci├│n, y hasta la normalizaci├│n del tr├ífico rodado a motor de explosi├│n (ese era el principal horizonte funcional del puente), se quedaba en medio un ratico "a ver si el puente aguanta". Otros, m├ís prudentes, observaban la riesgosa probanza desde la ribera. En la margen izquierda, imagen del barrio de la Hortilla, antes de perder la "h", del camping de Helios y, sobresaliendo de los ├írboles, de la chimenea de la antigua Manufacturas de lanas de Mor├│n y An├│s, en el Camino de Ranillas. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1967, 1967, 1967, 'Anos 60', 'CASCO HIST├ôRICO', 41.65835600, -0.88148800, '0101000020E610000058207A522635ECBF0C90680245D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15181013490.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15181013490.webp', 'https://www.flickr.com/photos/zaragozaantigua/15181013490/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24739, 'Ba├▒os p├║blicos 1930', 'Foto colecci├│n Luis Rasal, 1930. Edificio de los ba├▒os p├║blicos de Zaragoza a orillas del Ebro (durante la riada de 1930). Situado en la actual ubicaci├│n del Club Nataci├│n Helios, en la margen izquierda. Al fondo, el Pilar. Fuente: www.facebook.com/photo.php?fbid=820302567992370&set=o...', 1930, 1930, 1930, 'Anos 30', 'CASCO HIST├ôRICO', 41.65915600, -0.88227400, '0101000020E61000002A8E03AF963BECBF297B4B395FD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15259142238.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15259142238.webp', 'https://www.flickr.com/photos/zaragozaantigua/15259142238/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24782, 'Camino de Ranillas 1977', 'Imagen del pluricentenario camino de Ranillas, tras el cruce de la reciente avenida de los Pirineos abierta para tr├ífico rodado. A la izquierda, prolongaci├│n de la densa arboleda de Macanaz, y muros perimetrales de las instalaciones del C.N. Helios. A la derecha, el barrio de la Ortilla. Al fondo, la huerta y soto de Ranillas. El camino de Ranillas aparece muy despejado tras el derribo de las antiguas "Manufacturas de lanas de Mor├│n y An├│s", de las que s├│lo se dej├│ en pie su estilita chimenea, ya fuera de plano, hacia la derecha, como la recientemente clausurada y desmantelada l├¡nea del ferrocarril de los Enlaces. El crecimiento urban├¡stico de la Margen Izquierda, desde la construcci├│n del puente de Santiago y la apertura de la avenida de los Pirineos, en progresi├│n geom├®trica y en unos pocos a├▒os transform├│, de forma radical, toda esta parte de la periferia rururbana de la ciudad, hasta dejarla irreconocible. Una supuesta "actuaci├│n urgente" urban├¡stica supuso la desaparici├│n de los barrios de la Ortilla, y de Ranillas. Alguna d├®cada m├ís tarde, un gran evento expositivo se termin├│ de llevar por delante la tradicional huerta. Fuente visual: amable aportaci├│n personal de Pablo Vald├®s.', 1977, 1977, 1977, 'Anos 70', 'CASCO HIST├ôRICO', 41.66025800, -0.88142600, '0101000020E6100000D6027B4CA434ECBF10768A5583D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27263779605.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27263779605.webp', 'https://www.flickr.com/photos/zaragozaantigua/27263779605/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25417, 'Pasarela Ebro 1945', 'Imagen de la Pasarela Peatonal del Ebro. Se construy├│ en 1941, y comenz├│ a dar servicio en febrero de 1942, como forma de comunicar las dos riberas, entre el puente de las piedras, y el puente del ferrocarril.', 1945, 1945, 1945, 'Anos 40', 'CASCO HIST├ôRICO', 41.65902300, -0.88117100, '0101000020E61000002FE065868D32ECBFE9279CDD5AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15748629947.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15748629947.webp', 'https://www.flickr.com/photos/zaragozaantigua/15748629947/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25431, 'Pasarela de Macanaz a├▒os 40', 'Foto: Miguel Mar├¡n Chivite. Vista de la pasarela sobre el Ebro tomada desde la arboleda de Macanaz. Adem├ís del Torre├│n de la Zuda, podemos ver los edificios del paseo Echegaray y Caballero. Fuente: Archivo Heraldo de Arag├│n.', 1940, 1940, 1949, 'Anos 40', 'CASCO HIST├ôRICO', 41.65859700, -0.88151900, '0101000020E610000019AF79556735ECBF321F10E84CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21549406816.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21549406816.webp', 'https://www.flickr.com/photos/zaragozaantigua/21549406816/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25432, 'Pasarela Ebro c.1957', 'Imagen capturada en altura, desde el inmediato torre├│n de la Zuda, de la moderna pasarela peatonal para cruce en seco del r├¡o Ebro, entre la densa arboleda de Macanaz, al fondo, y la confluencia del paseo de Echegaray y Caballero y la V├¡a Imperial, antigua calle de Antonio P├®rez, en primer plano, donde la taquilla de peaje. A la izquierda, humea la chimenea fabril de "Manufacturas de lanas de Mor├│n y An├│s". Fuente visual: Teodoro Naranjo Dom├¡nguez, para ABC.', 1957, 1957, 1957, 'Anos 50', 'CASCO HIST├ôRICO', 41.65859700, -0.88151900, '0101000020E610000019AF79556735ECBF321F10E84CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24392641973.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24392641973.webp', 'https://www.flickr.com/photos/zaragozaantigua/24392641973/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25443, 'Pasarela del Ebro 1945', 'Imagen con el sonriente posado de varios oficiales del ej├®rcito de tierra (posiblemente, tenientes), en la pasarela peatonal recientemente tendida sobre el Ebro. Al fondo, el Pilar, y la nov├¡sima y enorme Hospeder├¡a del Pilar, cuyas dependencias se abren a tres fachadas, y con tres patios interiores. A su izquierda, m├ís tarde, se construir├¡a el edificio de las viviendas del Cabildo, y la nueva Casa de Infantes. A la derecha, fuera de plano, la iglesia de San Juan de los Panetes, y el antiguo embarcadero que, con la entrada en servicio de la pasarela, qued├│ obsoleto. Fuente visual: www.todocoleccion.net/', 1945, 1945, 1945, 'Anos 40', 'CASCO HIST├ôRICO', 41.65859700, -0.88151900, '0101000020E610000019AF79556735ECBF321F10E84CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30901004865.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30901004865.webp', 'https://www.flickr.com/photos/zaragozaantigua/30901004865/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25447, 'R├¡o Ebro 1921', 'Dibujo del arquitecto Antonio Seti├®n, realizado en Hernani en 1921. Ofrece un proyecto de navegabilidad del r├¡o Ebro, con un puente colgante. A la izquierda, c├║pulas y torre del Pilar. En la margen izquierda, un gran parque en los terrenos del futuro Club de Nataci├│n Helios. Fuente visual: Revista Relieves, n├║m. 2, 1933.', 1921, 1921, 1921, 'Anos 20', 'CASCO HIST├ôRICO', 41.65843000, -0.88077700, '0101000020E61000002F35423F532FECBF475A2A6F47D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32425819744.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32425819744.webp', 'https://www.flickr.com/photos/zaragozaantigua/32425819744/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25457, 'Pasarela de Macanaz 1949', 'Dibujo incluido en un art├¡culo referido a "La arquitectura de Zaragoza en estos ├║ltimos a├▒os", y justificado por la presencia de la pasarela de Macanaz, inaugurada en 1941. Bajo ella se representa la tradicional pr├íctica del transporte de maderas por el r├¡o Ebro, si bien en esta l├ímina la conducci├│n recae en embarcaciones a motor. Esta actividad fue realizada, entre otras cosas, hasta que la construcci├│n del embalse de Yesa cerr├│ el paso a los almadieros del valle del Roncal, que hasta aqu├¡ descend├¡an sus troncos. Tras la pasarela y en la margen derecha, el templo del Pilar y la tambi├®n reciente y hom├│nima Hospeder├¡a. Al fondo, el puente de Piedra. A la izquierda y en primer t├®rmino, un par de jubilados sentados en la arboleda de Macanaz contemplan la escena.', 1949, 1949, 1949, 'Anos 40', 'CASCO HIST├ôRICO', 41.65852500, -0.88135200, '0101000020E61000004374081C0934ECBF984C158C4AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50010448192.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50010448192.webp', 'https://www.flickr.com/photos/zaragozaantigua/50010448192/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
